CREATE OR REPLACE FUNCTION sync_module_discrepancy_note_to_discrepancy_note()
RETURNS TRIGGER AS $$
BEGIN
    IF (TG_OP = 'INSERT') THEN
        INSERT INTO discrepancy_note (
            discrepancy_note_id, description, discrepancy_note_type_id,
            resolution_status_id, detailed_notes, date_created, owner_id,
            parent_dn_id, entity_type, entity_id, study_id, assigned_user_id
        )
        VALUES (
            NEW.discrepancy_note_id, NEW.description, NEW.discrepancy_note_type_id,
            NEW.resolution_status_id, NEW.detailed_notes, NEW.date_created, NEW.owner_id,
            NEW.parent_dn_id, NEW.entity_type, NEW.entity_id, NEW.study_id, NEW.assigned_user_id
        );
        RETURN NEW;
    ELSIF (TG_OP = 'UPDATE') THEN
        UPDATE discrepancy_note SET
            description = NEW.description,
            discrepancy_note_type_id = NEW.discrepancy_note_type_id,
            resolution_status_id = NEW.resolution_status_id,
            detailed_notes = NEW.detailed_notes,
            date_created = NEW.date_created,
            owner_id = NEW.owner_id,
            parent_dn_id = NEW.parent_dn_id,
            entity_type = NEW.entity_type,
            entity_id = NEW.entity_id,
            study_id = NEW.study_id,
            assigned_user_id = NEW.assigned_user_id
        WHERE discrepancy_note_id = OLD.discrepancy_note_id;
        RETURN NEW;
    ELSIF (TG_OP = 'DELETE') THEN
        DELETE FROM discrepancy_note WHERE discrepancy_note_id = OLD.discrepancy_note_id;
        RETURN OLD;
    END IF;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_sync_module_discrepancy_note
AFTER INSERT OR UPDATE OR DELETE ON module_discrepancy_note
FOR EACH ROW EXECUTE FUNCTION sync_module_discrepancy_note_to_discrepancy_note();
